def get_keywords():
    # Helper to wrap in \b
    def w(words):
        return [r'\b' + word + r'\b' for word in words]

    return {
        'Sports': w([
            'sport', 'sports', 'football', 'baseball', 'basketball', 'soccer', 'tennis', 'golf', 'hockey', 
            'cricket', 'rugby', 'athlete', 'athletes', 'player', 'players', 'team', 'teams', 'coach', 'stadium', 'match', 'matches', 
