            'mlb', 'nhl', 'fifa', 'uefa', 'wimbledon', 'grand slam', 'race', 'racing', 'driver', 
            'boxing', 'wrestling', 'score', 'scores', 'victory', 'defeat', 'win', 'wins', 'winning', 'won', 'season', 'playoff', 
            'super bowl', 'world series', 'athens', 'games', 'game'
        ]),
